framework_css:
/*
    FloJam Legal Framework Styles
    This CSS file defines the global design system, header, and footer styles
    based on the provided legal website design.
*/

:root {
    /* Core palette extracted from the design */
    --color-black: #000000;
    --color-deep-red: #7C0505;          /* Primary navigation bar */
    --color-gold: #F4C542;              /* Logo accent, lines, small highlights */
    --color-warm-gold: #8C5A2E;         /* Secondary warm accent */
    --color-accent-cyan: #00A4D8;       /* Call-to-action buttons */

    --color-white: #FFFFFF;
    --color-offwhite: #F5F5F5;
    --color-text-main: #444444;

    /* Semantic colors */
    --color-success: #2E7D32;
    --color-error: #C62828;
    --color-warning: #ED6C02;
    --color-info: #0277BD;

    /* Typography scale */
    --font-heading-serif: 'Cinzel', Georgia, serif;
    --font-heading-sans: 'DM Sans', 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    --font-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;

    --font-size-h1: 2.375rem;  /* ~38px */
    --font-size-h2: 2rem;      /* 32px */
    --font-size-h3: 1.5rem;    /* 24px */
    --font-size-body: 1rem;    /* 16px */
    --font-size-small: 0.8125rem; /* 13px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-xxs: 0.25rem;  /* 4px */
    --space-xs: 0.5rem;    /* 8px */
    --space-sm: 1rem;      /* 16px */
    --space-md: 1.5rem;    /* 24px */
    --space-lg: 2rem;      /* 32px */
    --space-xl: 3rem;      /* 48px */
    --space-xxl: 4rem;     /* 64px */

    /* Layout */
    --container-max-width: 1200px;

    /* Borders & radii */
    --radius-sm: 3px;
    --radius-md: 4px;
}

/* Global reset & base styles */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-text-main);
    background-color: var(--color-offwhite);
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.container {
    max-width: var(--container-max-width);
    margin: 0 auto;
    padding: 0 var(--space-md);
}

.site-main {
    min-height: 50vh; /* allows main content to breathe between header and footer */
    padding: var(--space-xl) 0;
}

/* Header ----------------------------------------------------------- */

.site-header {
    font-family: var(--font-heading-sans);
    color: var(--color-white);
}

/* Top black bar (logo + contact information) */

.top-bar {
    background-color: var(--color-black);
    padding: var(--space-sm) 0;
}

.top-bar-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-lg);
}

.brand-block {
    display: flex;
    align-items: center;
    gap: var(--space-sm);
}

.brand-mark {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    border: 2px solid var(--color-gold);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--color-gold);
    font-family: var(--font-heading-serif);
    font-weight: 600;
    letter-spacing: 0.08em;
    font-size: 0.875rem;
}

.brand-mark-initials {
    text-transform: uppercase;
}

.brand-text {
    display: flex;
    flex-direction: column;
    line-height: var(--line-height-tight);
}

.brand-name {
    font-family: var(--font-heading-serif);
    font-size: 1.5rem;
    letter-spacing: 0.08em;
    color: var(--color-gold);
}

.brand-tagline {
    font-family: var(--font-heading-serif);
    font-size: 0.875rem;
    letter-spacing: 0.28em;
    text-transform: uppercase;
    margin-top: 2px;
}

.header-meta {
    text-align: right;
    font-size: var(--font-size-small);
    line-height: var(--line-height-relaxed);
}

.header-meta-line {
    color: var(--color-white);
}

.header-meta-strong {
    font-weight: 600;
}

/* Primary navigation bar (deep red) */

.primary-nav {
    background-color: var(--color-deep-red);
    border-top: 2px solid var(--color-gold);
    border-bottom: 2px solid var(--color-gold);
}

.nav-list {
    display: flex;
    flex-wrap: wrap;
    list-style: none;
    margin: 0;
    padding: 0;
}

.nav-item {
    margin: 0;
}

.nav-link {
    display: block;
    padding: 0.75rem 1.5rem; /* ~12-16px vertical, 24px horizontal */
    font-family: var(--font-heading-sans);
    font-size: 0.9375rem; /* 15px */
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: var(--color-white);
    font-weight: 600;
}

.nav-link:hover,
.nav-link:focus {
    background-color: #5c0303; /* slightly darker red on hover */
    color: var(--color-gold);
    text-decoration: none;
}

/* Optional class to mark the current page */

.nav-link.is-active {
    color: var(--color-gold);
    border-bottom: 3px solid var(--color-gold);
}

/* Footer ----------------------------------------------------------- */

.site-footer {
    background-color: #111111;
    color: var(--color-offwhite);
    font-family: var(--font-body);
}

.footer-main {
    border-top: 3px solid var(--color-gold);
    padding: var(--space-xl) 0 var(--space-lg);
}

.footer-inner {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: var(--space-xl);
}

.footer-brand {
    max-width: 360px;
}

.footer-brand-name {
    font-family: var(--font-heading-serif);
    font-size: 1.375rem;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    color: var(--color-gold);
    margin-bottom: var(--space-xs);
}

.footer-brand-tagline {
    font-family: var(--font-heading-serif);
    font-size: 0.875rem;
    letter-spacing: 0.28em;
    text-transform: uppercase;
    margin-bottom: var(--space-sm);
}

.footer-copy {
    font-size: 0.9375rem;
    line-height: var(--line-height-relaxed);
    margin: 0;
}

.footer-nav {
    flex: 1;
}

.footer-links {
    list-style: none;
    margin: 0;
    padding: 0;
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    column-gap: var(--space-lg);
    row-gap: var(--space-xs);
}

.footer-links a {
    font-size: 0.9375rem;
    color: var(--color-offwhite);
}

.footer-links a:hover,
.footer-links a:focus {
    color: var(--color-gold);
    text-decoration: none;
}

.footer-bottom {
    background-color: #080808;
    border-top: 1px solid #333333;
    padding: var(--space-sm) 0;
}

.footer-bottom-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--space-md);
    font-size: var(--font-size-small);
}

.footer-small-print {
    opacity: 0.8;
}

/* Utility: update year via server-side or JS as needed; CSS placeholder only */
#current-year {
    /* This element can be updated dynamically if desired. */
}

/* Buttons (for consistency with design, though not used directly in framework) */

.btn-primary {
    display: inline-block;
    padding: 0.9rem 2.5rem;
    background-color: var(--color-accent-cyan);
    color: var(--color-white);
    text-transform: uppercase;
    letter-spacing: 0.12em;
    font-family: var(--font-heading-sans);
    font-size: 0.9375rem;
    font-weight: 600;
    border-radius: var(--radius-md);
    border: none;
    cursor: pointer;
    text-align: center;
}

.btn-primary:hover,
.btn-primary:focus {
    background-color: #0087b3;
    text-decoration: none;
}

/* Responsive adjustments ------------------------------------------- */

@media (max-width: 900px) {
    .top-bar-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .header-meta {
        text-align: left;
    }

    .nav-link {
        padding-inline: 1rem;
    }
}

@media (max-width: 640px) {
    .footer-inner {
        flex-direction: column;
    }

    .footer-bottom-inner {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav-list {
        flex-wrap: wrap;
    }

    .nav-link {
        padding: 0.6rem 0.9rem;
        font-size: 0.875rem;
    }
}
